using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;public class ConsentServiceTests_CreateAccessRequest_DoctorToPatient_ShouldReturnMessage : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "ConsentService"    };    [SkippableFact]    public async Task CreateAccessRequest_DoctorToPatient_ShouldReturnMessage()    {    await AuthenticateAsDoctorAsync(ConsentClient);    var request = new    {    requesterId = TestSeedData.DoctorUserId,    requesterDid = $"did:dbh:user:{TestSeedData.DoctorUserId}",    requesterType = "DOCTOR",    patientId = TestSeedData.PatientUserId,    patientDid = $"did:dbh:user:{TestSeedData.PatientUserId}",    permission = "READ",    purpose = "TREATMENT",    reason = "Treatment",    requestedDurationDays = 7    };    var response = await PostAsJsonWithRetryAsync(ConsentClient, ApiEndpoints.AccessRequests.Create, request);        Assert.True(response.StatusCode == HttpStatusCode.Created || response.StatusCode == HttpStatusCode.OK || response.StatusCode == HttpStatusCode.BadRequest);    var json = await ReadJsonResponseAsync(response);    Assert.True(json.TryGetProperty("message", out _) || json.TryGetProperty("success", out _) || json.TryGetProperty("data", out _));    }}